126:   Upstream::HostDescriptionConstSharedPtr upstream_host_;
127:   // The gRPC status returned by the authorization server when it is making a gRPC call.
128:   absl::optional<Grpc::Status::GrpcStatus> grpc_status_;
129:   // True if the call failed open.
