318: /**
319:  * Per route settings for ExtAuth. Allows customizing the CheckRequest on a
320:  * virtualhost\route\weighted cluster level.
321:  */
322: class FilterConfigPerRoute : public Router::RouteSpecificFilterConfig {
323: public:
324:   using ContextExtensionsMap = Protobuf::Map<std::string, std::string>;
325: 
326:   FilterConfigPerRoute(
327:       const envoy::extensions::filters::http::ext_authz::v3::ExtAuthzPerRoute& config)
328:       : context_extensions_(config.has_check_settings()
329:                                 ? config.check_settings().context_extensions()
330:                                 : ContextExtensionsMap()),
331:         check_settings_(config.has_check_settings()
332:                             ? config.check_settings()
333:                             : envoy::extensions::filters::http::ext_authz::v3::CheckSettings()),
334:         disabled_(config.disabled()),
335:         grpc_service_(config.has_check_settings() && config.check_settings().has_grpc_service()
336:                           ? absl::make_optional(config.check_settings().grpc_service())
337:                           : absl::nullopt),
338:         http_service_(config.has_check_settings() && config.check_settings().has_http_service()
339:                           ? absl::make_optional(config.check_settings().http_service())
340:                           : absl::nullopt) {
341:     if (config.has_check_settings() && config.check_settings().disable_request_body_buffering() &&
342:         config.check_settings().has_with_request_body()) {
343:       ExceptionUtil::throwEnvoyException(
344:           "Invalid configuration for check_settings. Only one of disable_request_body_buffering or "
345:           "with_request_body can be set.");
346:     }
347:   }
348: 
349:   // This constructor is used as a way to merge more-specific config into less-specific config in a
350:   // clearly defined way (e.g. route config into VH config). All fields on this class must be const
351:   // and thus must be initialized in the constructor initialization list.
352:   FilterConfigPerRoute(const FilterConfigPerRoute& less_specific,
353:                        const FilterConfigPerRoute& more_specific);
354: 
355:   void merge(const FilterConfigPerRoute& other);
356: 
357:   /**
358:    * @return Context extensions to add to the CheckRequest.
359:    */
360:   const ContextExtensionsMap& contextExtensions() const { return context_extensions_; }
361:   // Allow moving the context extensions out of this object.
362:   ContextExtensionsMap&& takeContextExtensions() { return std::move(context_extensions_); }
363: 
364:   bool disabled() const { return disabled_; }
365: 
366:   const envoy::extensions::filters::http::ext_authz::v3::CheckSettings& checkSettings() const {
367:     return check_settings_;
368:   }
369: 
370:   /**
371:    * @return The gRPC service override for this route, if any.
372:    */
373:   const absl::optional<const envoy::config::core::v3::GrpcService>& grpcService() const {
374:     return grpc_service_;
375:   }
376: 
377:   /**
378:    * @return The HTTP service override for this route, if any.
379:    */
380:   const absl::optional<const envoy::extensions::filters::http::ext_authz::v3::HttpService>&
381:   httpService() const {
382:     return http_service_;
383:   }
384: 
385: private:
386:   // We save the context extensions as a protobuf map instead of a std::map as this allows us to
387:   // move it to the CheckRequest, thus avoiding a copy that would incur by converting it.
388:   ContextExtensionsMap context_extensions_;
389:   envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
390:   const bool disabled_;
391:   const absl::optional<const envoy::config::core::v3::GrpcService> grpc_service_;
392:   const absl::optional<const envoy::extensions::filters::http::ext_authz::v3::HttpService>
393:       http_service_;
394: };
