419:   Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
420:   Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
421:   void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;
422: 
423:   // Http::StreamEncoderFilter
424:   Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap& headers) override;
425:   Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
426:                                           bool end_stream) override;
427:   Http::FilterDataStatus encodeData(Buffer::Instance& data, bool end_stream) override;
428:   Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap& trailers) override;
429:   Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap& trailers) override;
430:   void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
431: 
432:   // ExtAuthz::RequestCallbacks
433:   void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
434: 
435: private:
436:   // Convenience function for the following:
437:   // 1. If `validate_mutations` is set to true, validate header key and value.
438:   // 2. If `decoder_header_mutation_rules` is set, check that mutation is allowed.
439:   Filters::Common::MutationRules::CheckResult
440:   validateAndCheckDecoderHeaderMutation(Filters::Common::MutationRules::CheckOperation operation,
441:                                         absl::string_view key, absl::string_view value) const;
442: 
443:   void responseHeaderLimitsReached();
444: 
445:   // Called when the filter is configured to reject invalid responses & the authz response contains
446:   // invalid header or query parameters. Sends a local response with the configured rejection status
447:   // code.
448:   void rejectResponse();
449: 
450:   // Validates error response headers and clears custom attributes if invalid headers are found.
451:   // Returns true if headers are valid or validation is disabled, false if headers are invalid.
452:   bool
453:   validateAndClearInvalidErrorResponseAttributes(Filters::Common::ExtAuthz::ResponsePtr& response);
454: 
455:   // Helper to check if we can add more headers to the response, respecting header limits.
456:   // Returns true if we can add more headers, false if the limit has been reached.
457:   bool canAddResponseHeader(Http::HeaderMap& response_headers);
458: 
459:   // Helper to add error response headers (both set and append) to the response header map,
460:   // respecting enforceResponseHeaderLimits().
461:   void addErrorResponseHeaders(
462:       Http::HeaderMap& response_headers,
463:       const std::vector<std::pair<std::string, std::string>>& headers_to_set,
464:       const std::vector<std::pair<std::string, std::string>>& headers_to_append);
465: 
466:   // Create a new gRPC client for per-route gRPC service configuration.
467:   Filters::Common::ExtAuthz::ClientPtr
468:   createPerRouteGrpcClient(const envoy::config::core::v3::GrpcService& grpc_service);
