33: void fillMetadataContext(const std::vector<const MetadataProto*>& source_metadata,
34:                          const std::vector<std::string>& metadata_context_namespaces,
35:                          const std::vector<std::string>& typed_metadata_context_namespaces,
36:                          MetadataProto& metadata_context) {
37:   for (const auto& context_key : metadata_context_namespaces) {
38:     for (const MetadataProto* metadata : source_metadata) {
39:       if (metadata == nullptr) {
40:         continue;
41:       }
42:       const auto& filter_metadata = metadata->filter_metadata();
43:       if (const auto metadata_it = filter_metadata.find(context_key);
44:           metadata_it != filter_metadata.end()) {
45:         (*metadata_context.mutable_filter_metadata())[metadata_it->first] = metadata_it->second;
46:         break;
47:       }
48:     }
49:   }
50: 
51:   for (const auto& context_key : typed_metadata_context_namespaces) {
52:     for (const MetadataProto* metadata : source_metadata) {
53:       if (metadata == nullptr) {
54:         continue;
55:       }
56:       const auto& typed_filter_metadata = metadata->typed_filter_metadata();
57:       if (const auto metadata_it = typed_filter_metadata.find(context_key);
58:           metadata_it != typed_filter_metadata.end()) {
59:         (*metadata_context.mutable_typed_filter_metadata())[metadata_it->first] =
60:             metadata_it->second;
61:         break;
62:       }
63:     }
64:   }
65: }
