79: FilterConfig::FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
80:                            Stats::Scope& scope, const std::string& stats_prefix,
81:                            Server::Configuration::ServerFactoryContext& factory_context)
