85:       clear_route_cache_(config.clear_route_cache()),
86:       max_request_bytes_(config.with_request_body().max_request_bytes()),
87:       max_denied_response_body_bytes_(config.max_denied_response_body_bytes()),
88: 
89:       // `pack_as_bytes_` should be true when configured with the HTTP service because there is no
90:       // difference to where the body is written in http requests, and a value of false here will
91:       // cause non UTF-8 body content to be changed when it doesn't need to.
92:       pack_as_bytes_(config.has_http_service() || config.with_request_body().pack_as_bytes()),
93: 
94:       encode_raw_headers_(config.encode_raw_headers()),
95: 
96:       status_on_error_(toErrorCode(config.status_on_error().code())),
97:       validate_mutations_(config.validate_mutations()), scope_(scope),
98:       decoder_header_mutation_checker_(
99:           config.has_decoder_header_mutation_rules()
100:               ? absl::optional<Filters::Common::MutationRules::Checker>(
101:                     Filters::Common::MutationRules::Checker(config.decoder_header_mutation_rules(),
102:                                                             factory_context.regexEngine()))
103:               : absl::nullopt),
104:       enable_dynamic_metadata_ingestion_(
105:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, enable_dynamic_metadata_ingestion, true)),
106:       runtime_(factory_context.runtime()), http_context_(factory_context.httpContext()),
107:       filter_metadata_(config.has_filter_metadata() ? absl::optional(config.filter_metadata())
108:                                                     : absl::nullopt),
109:       emit_filter_state_stats_(config.emit_filter_state_stats()),
110:       enforce_response_header_limits_(config.enforce_response_header_limits()),
111:       filter_enabled_(config.has_filter_enabled()
112:                           ? absl::optional<Runtime::FractionalPercent>(
113:                                 Runtime::FractionalPercent(config.filter_enabled(), runtime_))
114:                           : absl::nullopt),
115:       filter_enabled_metadata_(
116:           config.has_filter_enabled_metadata()
117:               ? absl::optional<Matchers::MetadataMatcher>(
118:                     Matchers::MetadataMatcher(config.filter_enabled_metadata(), factory_context))
119:               : absl::nullopt),
120:       deny_at_disable_(config.has_deny_at_disable()
121:                            ? absl::optional<Runtime::FeatureFlag>(
122:                                  Runtime::FeatureFlag(config.deny_at_disable(), runtime_))
123:                            : absl::nullopt),
124:       pool_(scope_.symbolTable()),
125:       metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
126:                                    config.metadata_context_namespaces().end()),
127:       typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
128:                                          config.typed_metadata_context_namespaces().end()),
129:       route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
130:                                          config.route_metadata_context_namespaces().end()),
131:       route_typed_metadata_context_namespaces_(
132:           config.route_typed_metadata_context_namespaces().begin(),
133:           config.route_typed_metadata_context_namespaces().end()),
134:       include_peer_certificate_(config.include_peer_certificate()),
135:       include_tls_session_(config.include_tls_session()),
136:       charge_cluster_response_stats_(
137:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, charge_cluster_response_stats, true)),
138:       stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
139:       ext_authz_ok_(pool_.add(createPoolStatName(config.stat_prefix(), "ok"))),
140:       ext_authz_denied_(pool_.add(createPoolStatName(config.stat_prefix(), "denied"))),
141:       ext_authz_error_(pool_.add(createPoolStatName(config.stat_prefix(), "error"))),
142:       ext_authz_invalid_(pool_.add(createPoolStatName(config.stat_prefix(), "invalid"))),
143:       ext_authz_failure_mode_allowed_(
144:           pool_.add(createPoolStatName(config.stat_prefix(), "failure_mode_allowed"))) {
145:   auto bootstrap = factory_context.bootstrap();
146:   auto labels_key_it =
147:       bootstrap.node().metadata().fields().find(config.bootstrap_metadata_labels_key());
148:   if (labels_key_it != bootstrap.node().metadata().fields().end()) {
149:     for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
150:       destination_labels_[labels_it.first] = labels_it.second.string_value();
151:     }
152:   }
153: 
154:   if (config.has_allowed_headers() &&
155:       config.http_service().authorization_request().has_allowed_headers()) {
156:     throw EnvoyException("Invalid duplicate configuration for allowed_headers.");
157:   }
158: 
159:   // An unset request_headers_matchers_ means that all client request headers are allowed through
160:   // to the authz server; this is to preserve backwards compatibility when introducing
161:   // allowlisting of request headers for gRPC authz servers. Pre-existing support is for
162:   // HTTP authz servers only and defaults to blocking all but a few headers (i.e. Authorization,
163:   // Method, Path and Host).
164:   if (config.has_grpc_service() && config.has_allowed_headers()) {
165:     allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
166:         config.allowed_headers(), false, factory_context);
167:   } else if (config.has_http_service()) {
168:     if (config.http_service().authorization_request().has_allowed_headers()) {
169:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
170:           config.http_service().authorization_request().allowed_headers(), true, factory_context);
171:     } else {
172:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
173:           config.allowed_headers(), true, factory_context);
174:     }
175:   }
176:   if (config.has_disallowed_headers()) {
177:     disallowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
178:         config.disallowed_headers(), false, factory_context);
179:   }
