182: void FilterConfigPerRoute::merge(const FilterConfigPerRoute& other) {
183:   // We only merge context extensions here, and leave boolean flags untouched since those flags are
184:   // not used from the merged config.
185:   auto begin_it = other.context_extensions_.begin();
186:   auto end_it = other.context_extensions_.end();
187:   for (auto it = begin_it; it != end_it; ++it) {
