192: // Constructor used for merging configurations from different levels (vhost, route, etc.)
193: FilterConfigPerRoute::FilterConfigPerRoute(const FilterConfigPerRoute& less_specific,
194:                                            const FilterConfigPerRoute& more_specific)
195:     : context_extensions_(less_specific.context_extensions_),
196:       check_settings_(more_specific.check_settings_), disabled_(more_specific.disabled_),
197:       // Only use the most specific per-route override. Do not inherit overrides from less
198:       // specific configuration. If the more specific configuration has no override, leave both
199:       // unset so that the main filter configuration is used.
200:       grpc_service_(more_specific.grpc_service_.has_value() ? more_specific.grpc_service_
201:                                                             : absl::nullopt),
202:       http_service_(more_specific.http_service_.has_value() ? more_specific.http_service_
203:                                                             : absl::nullopt) {
204:   // Merge context extensions from more specific configuration, overriding less specific ones.
205:   for (const auto& extension : more_specific.context_extensions_) {
206:     context_extensions_[extension.first] = extension.second;
207:   }
