210: Filters::Common::ExtAuthz::ClientPtr
211: Filter::createPerRouteGrpcClient(const envoy::config::core::v3::GrpcService& grpc_service) {
212:   if (server_context_ == nullptr) {
213:     ENVOY_STREAM_LOG(
214:         debug, "ext_authz filter: server context not available for per-route gRPC client creation.",
215:         *decoder_callbacks_);
216:     return nullptr;
217:   }
218: 
219:   // Use the timeout from the gRPC service configuration, use default if not specified.
220:   // A timeout of 0 means infinite (no timeout). Convert to nullopt in that case.
221:   const uint32_t timeout_ms =
222:       PROTOBUF_GET_MS_OR_DEFAULT(grpc_service, timeout, kDefaultPerRouteTimeoutMs);
223:   const absl::optional<std::chrono::milliseconds> timeout =
224:       timeout_ms == 0
225:           ? absl::nullopt
226:           : absl::optional<std::chrono::milliseconds>(std::chrono::milliseconds(timeout_ms));
227: 
228:   // We can skip transport version check for per-route gRPC service here.
229:   // The transport version is already validated at the main configuration level.
230:   Envoy::Grpc::GrpcServiceConfigWithHashKey config_with_hash_key =
231:       Envoy::Grpc::GrpcServiceConfigWithHashKey(grpc_service);
232: 
233:   auto client_or_error = server_context_->clusterManager()
234:                              .grpcAsyncClientManager()
235:                              .getOrCreateRawAsyncClientWithHashKey(config_with_hash_key,
236:                                                                    server_context_->scope(), true);
237:   if (!client_or_error.ok()) {
238:     ENVOY_STREAM_LOG(warn,
239:                      "ext_authz filter: failed to create per-route gRPC client: {}. Falling back "
240:                      "to default client.",
241:                      *decoder_callbacks_, client_or_error.status().ToString());
242:     return nullptr;
243:   }
244: 
245:   ENVOY_STREAM_LOG(debug, "ext_authz filter: created per-route gRPC client for cluster: {}.",
246:                    *decoder_callbacks_,
247:                    grpc_service.has_envoy_grpc() ? grpc_service.envoy_grpc().cluster_name()
248:                                                  : "google_grpc");
249: 
250:   return std::make_unique<Filters::Common::ExtAuthz::GrpcClientImpl>(client_or_error.value(),
251:                                                                      timeout);
252: }
