277: void Filter::initiateCall(const Http::RequestHeaderMap& headers) {
278:   if (filter_return_ == FilterReturn::StopDecoding) {
279:     return;
280:   }
281: 
282:   // Now that we'll definitely be making the request, add filter state stats if configured to do so.
283:   const Envoy::StreamInfo::FilterStateSharedPtr& filter_state =
284:       decoder_callbacks_->streamInfo().filterState();
285:   if ((config_->emitFilterStateStats() || config_->filterMetadata().has_value())) {
286:     if (!filter_state->hasData<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName())) {
287:       filter_state->setData(decoder_callbacks_->filterConfigName(),
288:                             std::make_shared<ExtAuthzLoggingInfo>(config_->filterMetadata()),
289:                             Envoy::StreamInfo::FilterState::StateType::Mutable,
290:                             Envoy::StreamInfo::FilterState::LifeSpan::Request);
291: 
292:       // This may return nullptr (if there's a value at this name whose type doesn't match or isn't
293:       // mutable, for example), so we must check logging_info_ is not nullptr later.
294:       logging_info_ =
295:           filter_state->getDataMutable<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName());
296:     }
297:     if (logging_info_ == nullptr) {
298:       stats_.filter_state_name_collision_.inc();
299:       ENVOY_STREAM_LOG(debug,
300:                        "Could not find logging info at {}! (Did another filter already put data "
301:                        "at this name?)",
302:                        *decoder_callbacks_, decoder_callbacks_->filterConfigName());
303:     }
304:   }
305: 
306:   absl::optional<FilterConfigPerRoute> maybe_merged_per_route_config;
307:   for (const FilterConfigPerRoute& cfg :
308:        Http::Utility::getAllPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_)) {
309:     if (maybe_merged_per_route_config.has_value()) {
310:       FilterConfigPerRoute current_config = maybe_merged_per_route_config.value();
311:       maybe_merged_per_route_config.emplace(current_config, cfg);
312:     } else {
313:       maybe_merged_per_route_config.emplace(cfg);
314:     }
315:   }
316: 
317:   Protobuf::Map<std::string, std::string> context_extensions;
318:   if (maybe_merged_per_route_config) {
319:     context_extensions = maybe_merged_per_route_config.value().takeContextExtensions();
320:   }
321: 
322:   // Check if we need to use a per-route service override (gRPC or HTTP).
323:   if (maybe_merged_per_route_config) {
324:     if (maybe_merged_per_route_config->grpcService().has_value()) {
325:       const auto& grpc_service = maybe_merged_per_route_config->grpcService().value();
326:       ENVOY_STREAM_LOG(debug, "ext_authz filter: using per-route gRPC service configuration.",
327:                        *decoder_callbacks_);
328: 
329:       // Create a new gRPC client for this route.
330:       auto per_route_client = createPerRouteGrpcClient(grpc_service);
331:       if (per_route_client != nullptr) {
332:         client_ = std::move(per_route_client);
333:         ENVOY_STREAM_LOG(debug, "ext_authz filter: successfully created per-route gRPC client.",
334:                          *decoder_callbacks_);
335:       } else {
336:         ENVOY_STREAM_LOG(
337:             warn,
338:             "ext_authz filter: failed to create per-route gRPC client, falling back to default.",
339:             *decoder_callbacks_);
340:       }
341:     } else if (maybe_merged_per_route_config->httpService().has_value()) {
342:       const auto& http_service = maybe_merged_per_route_config->httpService().value();
343:       ENVOY_STREAM_LOG(debug, "ext_authz filter: using per-route HTTP service configuration.",
344:                        *decoder_callbacks_);
345: 
346:       // Create a new HTTP client for this route.
347:       auto per_route_client = createPerRouteHttpClient(http_service);
348:       if (per_route_client != nullptr) {
349:         client_ = std::move(per_route_client);
350:         ENVOY_STREAM_LOG(debug, "ext_authz filter: successfully created per-route HTTP client.",
351:                          *decoder_callbacks_);
352:       } else {
353:         ENVOY_STREAM_LOG(
354:             warn,
355:             "ext_authz filter: failed to create per-route HTTP client, falling back to default.",
356:             *decoder_callbacks_);
357:       }
358:     }
359:   }
360: 
361:   // If metadata_context_namespaces or typed_metadata_context_namespaces is specified,
362:   // pass matching filter metadata to the ext_authz service.
363:   // If metadata key is set in both the connection and request metadata,
364:   // then the value will be the request metadata value.
365:   envoy::config::core::v3::Metadata metadata_context;
366:   fillMetadataContext({&decoder_callbacks_->streamInfo().dynamicMetadata(),
367:                        &decoder_callbacks_->connection()->streamInfo().dynamicMetadata()},
368:                       config_->metadataContextNamespaces(),
369:                       config_->typedMetadataContextNamespaces(), metadata_context);
370: 
371:   // Fill route_metadata_context from the selected route's metadata.
372:   envoy::config::core::v3::Metadata route_metadata_context;
373:   if (decoder_callbacks_->route() != nullptr) {
374:     fillMetadataContext({&decoder_callbacks_->route()->metadata()},
375:                         config_->routeMetadataContextNamespaces(),
376:                         config_->routeTypedMetadataContextNamespaces(), route_metadata_context);
377:   }
378: 
379:   Filters::Common::ExtAuthz::CheckRequestUtils::createHttpCheck(
380:       decoder_callbacks_, headers, std::move(context_extensions), std::move(metadata_context),
381:       std::move(route_metadata_context), check_request_, max_request_bytes_, config_->packAsBytes(),
382:       config_->headersAsBytes(), config_->includePeerCertificate(), config_->includeTLSSession(),
383:       config_->destinationLabels(), config_->allowedHeadersMatcher(),
384:       config_->disallowedHeadersMatcher());
385: 
386:   ENVOY_STREAM_LOG(trace, "ext_authz filter calling authorization server.", *decoder_callbacks_);
387:   // Store start time of ext_authz filter call
388:   start_time_ = decoder_callbacks_->dispatcher().timeSource().monotonicTime();
389: 
390:   state_ = State::Calling;
391:   filter_return_ = FilterReturn::StopDecoding; // Don't let the filter chain continue as we are
392:                                                // going to invoke check call.
393:   cluster_ = decoder_callbacks_->clusterInfo();
394:   initiating_call_ = true;
395:   client_->check(*this, check_request_, decoder_callbacks_->activeSpan(),
396:                  decoder_callbacks_->streamInfo());
397:   initiating_call_ = false;
398: }
