400: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
401:   Router::RouteConstSharedPtr route = decoder_callbacks_->route();
402:   const auto per_route_flags = getPerRouteFlags(route);
403:   skip_check_ = per_route_flags.skip_check_;
404:   if (skip_check_) {
405:     return Http::FilterHeadersStatus::Continue;
406:   }
407: 
408:   if (!config_->filterEnabled(decoder_callbacks_->streamInfo().dynamicMetadata())) {
409:     stats_.disabled_.inc();
410:     if (config_->denyAtDisable()) {
411:       ENVOY_STREAM_LOG(trace, "ext_authz filter is disabled. Deny the request.",
412:                        *decoder_callbacks_);
413:       decoder_callbacks_->streamInfo().setResponseFlag(
414:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
415:       decoder_callbacks_->sendLocalReply(
416:           config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
417:           Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
418:       return Http::FilterHeadersStatus::StopIteration;
419:     }
420:     return Http::FilterHeadersStatus::Continue;
421:   }
422: 
423:   request_headers_ = &headers;
424:   const auto& check_settings = per_route_flags.check_settings_;
425:   buffer_data_ = (config_->withRequestBody() || check_settings.has_with_request_body()) &&
426:                  !check_settings.disable_request_body_buffering() &&
427:                  !(end_stream || Http::Utility::isWebSocketUpgradeRequest(headers) ||
428:                    Http::Utility::isH2UpgradeRequest(headers));
429: 
430:   max_request_bytes_ = config_->maxRequestBytes();
431:   if (buffer_data_) {
432:     ENVOY_STREAM_LOG(debug, "ext_authz filter is buffering the request", *decoder_callbacks_);
433: 
434:     allow_partial_message_ = check_settings.has_with_request_body()
435:                                  ? check_settings.with_request_body().allow_partial_message()
436:                                  : config_->allowPartialMessage();
437:     if (check_settings.has_with_request_body()) {
438:       max_request_bytes_ = check_settings.with_request_body().max_request_bytes();
439:     }
440:     if (!allow_partial_message_) {
441:       decoder_callbacks_->setBufferLimit(max_request_bytes_);
442:     }
443:     return Http::FilterHeadersStatus::StopIteration;
444:   }
445: 
446:   // Initiate a call to the authorization server since we are not disabled.
447:   initiateCall(headers);
448:   return filter_return_ == FilterReturn::StopDecoding
449:              ? Http::FilterHeadersStatus::StopAllIterationAndWatermark
450:              : Http::FilterHeadersStatus::Continue;
451: }
