453: Http::FilterDataStatus Filter::decodeData(Buffer::Instance& data, bool end_stream) {
454:   if (buffer_data_ && !skip_check_) {
455:     const bool buffer_is_full = isBufferFull(data.length());
456:     if (end_stream || buffer_is_full) {
457:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request since {}",
458:                        *decoder_callbacks_, buffer_is_full ? "buffer is full" : "stream is ended");
459:       // Make sure data is available in initiateCall.
460:       decoder_callbacks_->addDecodedData(data, true);
461:       initiateCall(*request_headers_);
462:       return filter_return_ == FilterReturn::StopDecoding
463:                  ? Http::FilterDataStatus::StopIterationAndWatermark
464:                  : Http::FilterDataStatus::Continue;
465:     } else {
466:       return Http::FilterDataStatus::StopIterationAndBuffer;
467:     }
468:   }
469: 
470:   return Http::FilterDataStatus::Continue;
471: }
472: 
473: Http::FilterTrailersStatus Filter::decodeTrailers(Http::RequestTrailerMap&) {
474:   if (buffer_data_ && !skip_check_) {
475:     if (filter_return_ != FilterReturn::StopDecoding) {
476:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request",
477:                        *decoder_callbacks_);
478:       initiateCall(*request_headers_);
479:     }
480:     return filter_return_ == FilterReturn::StopDecoding ? Http::FilterTrailersStatus::StopIteration
481:                                                         : Http::FilterTrailersStatus::Continue;
482:   }
483: 
484:   return Http::FilterTrailersStatus::Continue;
485: }
