579: void Filter::updateLoggingInfo(const absl::optional<Grpc::Status::GrpcStatus>& grpc_status) {
580:   if (!config_->emitFilterStateStats()) {
581:     return;
582:   }
583: 
584:   if (logging_info_ == nullptr) {
585:     return;
586:   }
587: 
588:   if (grpc_status.has_value()) {
589:     logging_info_->setGrpcStatus(grpc_status.value());
590:   }
591: 
592:   // Latency is the only stat available if we aren't using envoy grpc.
593:   if (start_time_.has_value()) {
594:     logging_info_->setLatency(std::chrono::duration_cast<std::chrono::microseconds>(
595:         decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value()));
596:   }
597: 
598:   auto const* stream_info = client_->streamInfo();
599:   if (stream_info == nullptr) {
600:     return;
601:   }
602: 
603:   const auto& bytes_meter = stream_info->getUpstreamBytesMeter();
604:   if (bytes_meter != nullptr) {
605:     logging_info_->setBytesSent(bytes_meter->wireBytesSent());
606:     logging_info_->setBytesReceived(bytes_meter->wireBytesReceived());
607:   }
608:   if (stream_info->upstreamInfo().has_value()) {
609:     logging_info_->setUpstreamHost(stream_info->upstreamInfo()->upstreamHost());
610:   }
611:   absl::optional<Upstream::ClusterInfoConstSharedPtr> cluster_info =
612:       stream_info->upstreamClusterInfo();
613:   if (cluster_info) {
614:     logging_info_->setClusterInfo(std::move(*cluster_info));
615:   }
616: }
