629: CheckResult Filter::validateAndCheckDecoderHeaderMutation(
630:     Filters::Common::MutationRules::CheckOperation operation, absl::string_view key,
631:     absl::string_view value) const {
632:   if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
633:                                        !Http::HeaderUtility::headerValueIsValid(value))) {
634:     return CheckResult::FAIL;
635:   }
636:   // Check header mutation is valid according to configured decoder mutation rules.
637:   return config_->checkDecoderHeaderMutation(operation, Http::LowerCaseString(key), value);
638: }
