640: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
641:   state_ = State::Complete;
642:   using Filters::Common::ExtAuthz::CheckStatus;
643:   Stats::StatName empty_stat_name;
644: 
645:   updateLoggingInfo(response->grpc_status);
646: 
647:   if (response->saw_invalid_append_actions) {
648:     if (config_->validateMutations()) {
649:       ENVOY_STREAM_LOG(trace, "Rejecting response with invalid header append action.",
650:                        *decoder_callbacks_);
651:       rejectResponse();
652:       updateEffect(Effect::InvalidMutationRejected);
653:       return;
654:     }
655:     ENVOY_STREAM_LOG(trace, "Ignoring response headers with invalid header append action.",
656:                      *decoder_callbacks_);
657:   }
658: 
659:   if (!response->dynamic_metadata.fields().empty()) {
660:     if (!config_->enableDynamicMetadataIngestion()) {
661:       ENVOY_STREAM_LOG(trace,
662:                        "Response is trying to inject dynamic metadata, but dynamic metadata "
663:                        "ingestion is disabled. Ignoring...",
664:                        *decoder_callbacks_);
665:       stats_.ignored_dynamic_metadata_.inc();
666:     } else {
667:       // Add duration of call to dynamic metadata if applicable
668:       if (start_time_.has_value() && response->status == CheckStatus::OK) {
669:         Protobuf::Value ext_authz_duration_value;
670:         auto duration =
671:             decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
672:         ext_authz_duration_value.set_number_value(
673:             std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
674:         (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
675:             ext_authz_duration_value;
676:       }
677:       decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
678:                                                           response->dynamic_metadata);
679:     }
680:   }
681:   switch (response->status) {
682:   case CheckStatus::OK: {
683:     // Any changes to request headers or query parameters can affect how the request is going to be
684:     // routed. If we are changing the headers we also need to clear the route
685:     // cache.
686:     if (config_->clearRouteCache() &&
687:         (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
688:          !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
689:          !response->query_parameters_to_remove.empty())) {
690:       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
691:       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
692:     }
693:     // Use this to track if there are any modifications to the request headers.
694:     bool req_header_mutations = false;
695:     ENVOY_STREAM_LOG(trace,
696:                      "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
697:     for (const auto& [key, value] : response->headers_to_set) {
698:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
699:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
700:       switch (check_result) {
701:       case CheckResult::OK:
702:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
703:         request_headers_->setCopy(Http::LowerCaseString(key), value);
704:         req_header_mutations = true;
705:         if (!headersWithinLimits(*request_headers_)) {
706:           stats_.request_header_limits_reached_.inc();
707:           rejectResponse();
708:           updateEffect(Effect::MutationRejectedSizeLimitExceeded);
709:           return;
710:         }
711:         break;
712:       case CheckResult::IGNORE:
713:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
714:                          key, value);
715:         break;
716:       case CheckResult::FAIL:
717:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
718:                          key, value);
719:         rejectResponse();
720:         updateEffect(Effect::InvalidMutationRejected);
721:         return;
722:       }
723:     }
724:     for (const auto& [key, value] : response->headers_to_add) {
725:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
726:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
727:       switch (check_result) {
728:       case CheckResult::OK:
729:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
730:         request_headers_->addCopy(Http::LowerCaseString(key), value);
731:         req_header_mutations = true;
732:         if (!headersWithinLimits(*request_headers_)) {
733:           stats_.request_header_limits_reached_.inc();
734:           rejectResponse();
735:           updateEffect(Effect::MutationRejectedSizeLimitExceeded);
736:           return;
737:         }
738:         break;
739:       case CheckResult::IGNORE:
740:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
741:                          key, value);
742:         break;
743:       case CheckResult::FAIL:
744:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
745:                          key, value);
746:         rejectResponse();
747:         updateEffect(Effect::InvalidMutationRejected);
748:         return;
749:       }
750:     }
751:     for (const auto& [key, value] : response->headers_to_append) {
752:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
753:           Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
754:       switch (check_result) {
755:       case CheckResult::OK: {
756:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
757:         Http::LowerCaseString lowercase_key(key);
758:         const auto header_to_modify = request_headers_->get(lowercase_key);
759:         // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
760:         // first (via `headers_to_add`). For example, given:
761:         // 1. Original headers {"original": "true"}
762:         // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
763:         // "2"}}
764:         //
765:         // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
766:         // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
767:         // "2"}}) to the request to upstream server by only sets `headers_to_append`.
768:         if (!header_to_modify.empty()) {
769:           ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
770:           // The current behavior of appending is by combining entries with the same key,
771:           // into one entry. The value of that combined entry is separated by ",".
772:           // TODO(dio): Consider to use addCopy instead.
773:           request_headers_->appendCopy(lowercase_key, value);
774:           req_header_mutations = true;
775:           if (!headersWithinLimits(*request_headers_)) {
776:             stats_.request_header_limits_reached_.inc();
777:             rejectResponse();
778:             updateEffect(Effect::MutationRejectedSizeLimitExceeded);
779:             return;
780:           }
781:         }
782:         break;
783:       }
784:       case CheckResult::IGNORE:
785:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to append '{}':'{}'.", *decoder_callbacks_,
786:                          key, value);
787:         break;
788:       case CheckResult::FAIL:
789:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to append '{}':'{}'.",
790:                          *decoder_callbacks_, key, value);
791:         rejectResponse();
792:         updateEffect(Effect::InvalidMutationRejected);
793:         return;
794:       }
795:     }
796: 
797:     ENVOY_STREAM_LOG(trace,
798:                      "ext_authz filter removed header(s) from the request:", *decoder_callbacks_);
799:     for (const auto& key : response->headers_to_remove) {
800:       // If the response contains an invalid header to remove, it's the same as trying to remove a
801:       // header that doesn't exist, so just ignore it.
802:       if (config_->validateMutations() && !Http::HeaderUtility::headerNameIsValid(key)) {
803:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
804:         continue;
805:       }
806:       // We don't allow removing any :-prefixed headers, nor Host, as removing them would make the
807:       // request malformed. checkDecoderHeaderMutation also performs this check, however, so only
808:       // perform this check explicitly if decoder header mutation rules is empty.
809:       if (!config_->hasDecoderHeaderMutationRules() &&
810:           !Http::HeaderUtility::isRemovableHeader(key)) {
811:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
812:         continue;
813:       }
814:       // Check header mutation is valid according to configured decoder header mutation rules.
815:       Http::LowerCaseString lowercase_key(key);
816:       switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
817:                                                   EMPTY_STRING)) {
818:       case CheckResult::OK:
819:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
820:         request_headers_->remove(lowercase_key);
821:         req_header_mutations = true;
822:         if (!headersWithinLimits(*request_headers_)) {
823:           stats_.request_header_limits_reached_.inc();
824:           rejectResponse();
825:           updateEffect(Effect::MutationRejectedSizeLimitExceeded);
826:           return;
827:         }
828:         break;
829:       case CheckResult::IGNORE:
830:         ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
831:                          key);
832:         break;
833:       case CheckResult::FAIL:
834:         ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
835:                          key);
836:         rejectResponse();
837:         updateEffect(Effect::InvalidMutationRejected);
838:         return;
839:       }
840:     }
841:     if (req_header_mutations) {
842:       updateEffect(Effect::MutationApplied);
843:     }
844: 
845:     if (!response->response_headers_to_add.empty()) {
846:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
847:                        *decoder_callbacks_, response->response_headers_to_add.size());
848:       for (const auto& [key, value] : response->response_headers_to_add) {
849:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
850:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
851:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
852:                            value);
853:           rejectResponse();
854:           return;
855:         }
856:       }
857:       response_headers_to_add_ = Http::HeaderVector{response->response_headers_to_add.begin(),
858:                                                     response->response_headers_to_add.end()};
859:     }
860: 
861:     if (!response->response_headers_to_set.empty()) {
862:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
863:                        *decoder_callbacks_, response->response_headers_to_set.size());
864:       for (const auto& [key, value] : response->response_headers_to_set) {
865:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
866:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
867:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
868:                            value);
869:           rejectResponse();
870:           return;
871:         }
872:       }
873:       response_headers_to_set_ = Http::HeaderVector{response->response_headers_to_set.begin(),
874:                                                     response->response_headers_to_set.end()};
875:     }
876: 
877:     if (!response->response_headers_to_add_if_absent.empty()) {
878:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
879:                        *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
880:       for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
881:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
882:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
883:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
884:                            value);
885:           rejectResponse();
886:           return;
887:         }
888:       }
889:       response_headers_to_add_if_absent_ =
890:           Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
891:                              response->response_headers_to_add_if_absent.end()};
892:     }
893: 
894:     if (!response->response_headers_to_overwrite_if_exists.empty()) {
895:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
896:                        *decoder_callbacks_,
897:                        response->response_headers_to_overwrite_if_exists.size());
898:       for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
899:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
900:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
901:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
902:                            value);
903:           rejectResponse();
904:           return;
905:         }
906:       }
907:       response_headers_to_overwrite_if_exists_ =
908:           Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
909:                              response->response_headers_to_overwrite_if_exists.end()};
910:     }
911: 
912:     absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
913:     if (!response->query_parameters_to_set.empty()) {
914:       modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
915:           request_headers_->Path()->value().getStringView());
916:       ENVOY_STREAM_LOG(
917:           trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
918:       for (const auto& [key, value] : response->query_parameters_to_set) {
919:         if (config_->validateMutations() &&
920:             (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
921:              !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
922:           ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
923:                            key, value);
924:           rejectResponse();
925:           updateEffect(Effect::InvalidMutationRejected);
926:           return;
927:         }
928:         ENVOY_STREAM_LOG(trace, "'{}={}'", *decoder_callbacks_, key, value);
929:         modified_query_parameters->overwrite(key, value);
930:       }
931:     }
932: 
933:     if (!response->query_parameters_to_remove.empty()) {
