23: Http::FilterFactoryCb ExtAuthzFilterConfig::createFilterFactoryFromProtoWithServerContextTyped(
24:     const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& proto_config,
25:     const std::string& stats_prefix, Server::Configuration::ServerFactoryContext& server_context) {
26:   const auto filter_config = std::make_shared<FilterConfig>(proto_config, server_context.scope(),
27:                                                             stats_prefix, server_context);
28:   // The callback is created in main thread and executed in worker thread, variables except factory
29:   // context must be captured by value into the callback.
30:   Http::FilterFactoryCb callback;
31:   if (proto_config.has_http_service()) {
32:     // Raw HTTP client.
33:     // A timeout of 0 means infinite (no timeout).
34:     const uint32_t timeout_ms = PROTOBUF_GET_MS_OR_DEFAULT(proto_config.http_service().server_uri(),
35:                                                            timeout, DefaultTimeout);
36:     const auto client_config =
37:         std::make_shared<Extensions::Filters::Common::ExtAuthz::ClientConfig>(
38:             proto_config, timeout_ms, proto_config.http_service().path_prefix(), server_context);
39:     callback = [filter_config = std::move(filter_config), client_config,
40:                 &server_context](Http::FilterChainFactoryCallbacks& callbacks) {
41:       auto client = std::make_unique<Extensions::Filters::Common::ExtAuthz::RawHttpClientImpl>(
42:           server_context.clusterManager(), client_config);
43:       callbacks.addStreamFilter(
44:           std::make_shared<Filter>(filter_config, std::move(client), server_context));
45:     };
46:   } else {
47:     // gRPC client.
48:     // A timeout of 0 means infinite (no timeout). Convert to nullopt in that case.
49:     const uint32_t timeout_ms =
50:         PROTOBUF_GET_MS_OR_DEFAULT(proto_config.grpc_service(), timeout, DefaultTimeout);
51:     const absl::optional<std::chrono::milliseconds> timeout =
52:         timeout_ms == 0
53:             ? absl::nullopt
54:             : absl::optional<std::chrono::milliseconds>(std::chrono::milliseconds(timeout_ms));
55:     THROW_IF_NOT_OK(Config::Utility::checkTransportVersion(proto_config));
56:     Envoy::Grpc::GrpcServiceConfigWithHashKey config_with_hash_key =
57:         Envoy::Grpc::GrpcServiceConfigWithHashKey(proto_config.grpc_service());
58:     callback = [&server_context, filter_config = std::move(filter_config), timeout,
59:                 config_with_hash_key](Http::FilterChainFactoryCallbacks& callbacks) {
60:       auto client_or_error = server_context.clusterManager()
61:                                  .grpcAsyncClientManager()
62:                                  .getOrCreateRawAsyncClientWithHashKey(
63:                                      config_with_hash_key, server_context.scope(), true);
64:       THROW_IF_NOT_OK_REF(client_or_error.status());
65:       auto client = std::make_unique<Filters::Common::ExtAuthz::GrpcClientImpl>(
66:           client_or_error.value(), timeout);
67:       callbacks.addStreamFilter(
68:           std::make_shared<Filter>(filter_config, std::move(client), server_context));
69:     };
70:   }
71:   return callback;
72: }
