79:   bool failureModeAllow() const { return failure_mode_allow_; }
80:   void setFailModeAllow(bool value) { failure_mode_allow_ = value; }
81:   bool includePeerCertificate() const { return include_peer_certificate_; }
82:   bool includeTLSSession() const { return include_tls_session_; }
83:   bool sendTlsAlertOnDenial() const { return send_tls_alert_on_denial_; }
84:   const LabelsMap& destinationLabels() const { return destination_labels_; }
85:   bool filterEnabledMetadata(const envoy::config::core::v3::Metadata& metadata) const {
86:     return filter_enabled_metadata_.has_value() ? filter_enabled_metadata_->match(metadata) : true;
87:   }
88:   const std::vector<std::string>& metadataContextNamespaces() const {
89:     return metadata_context_namespaces_;
90:   }
