110: /**
111:  * ExtAuthz filter instance. This filter will call the Authorization service with the given
112:  * configuration parameters. If the authorization service returns an error or a deny the
113:  * connection will be closed without any further filters being called. Otherwise all buffered
114:  * data will be released to further filters.
115:  */
116: class Filter : public Network::ReadFilter,
117:                public Network::ConnectionCallbacks,
118:                public Filters::Common::ExtAuthz::RequestCallbacks {
119:   using LabelsMap = std::map<std::string, std::string>;
120: 
121: public:
122:   Filter(ConfigSharedPtr config, Filters::Common::ExtAuthz::ClientPtr&& client)
123:       : config_(config), client_(std::move(client)) {}
124:   ~Filter() override = default;
125: 
126:   // Network::ReadFilter
127:   Network::FilterStatus onData(Buffer::Instance& data, bool end_stream) override;
128:   Network::FilterStatus onNewConnection() override;
129:   void initializeReadFilterCallbacks(Network::ReadFilterCallbacks& callbacks) override {
130:     filter_callbacks_ = &callbacks;
131:     filter_callbacks_->connection().addConnectionCallbacks(*this);
132:   }
133: 
134:   // Network::ConnectionCallbacks
135:   void onEvent(Network::ConnectionEvent event) override;
136:   void onAboveWriteBufferHighWatermark() override {}
137:   void onBelowWriteBufferLowWatermark() override {}
138: 
139:   // ExtAuthz::RequestCallbacks
140:   void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
141: 
142: private:
143:   // State of this filter's communication with the external authorization service.
144:   // The filter has either not started calling the external service, in the middle of calling
145:   // it or has completed.
146:   enum class Status { NotStarted, Calling, Complete };
147:   // FilterReturn is used to capture what the return code should be to the filter chain.
148:   // if this filter is either in the middle of calling the external service or the result is denied
149:   // then the filter chain should stop. Otherwise the filter chain can continue to the next filter.
150:   enum class FilterReturn { Stop, Continue };
151:   void callCheck();
152: 
153:   bool filterEnabled(const envoy::config::core::v3::Metadata& metadata) {
154:     return config_->filterEnabledMetadata(metadata);
155:   }
156:   absl::optional<MonotonicTime> start_time_;
157: 
158:   ConfigSharedPtr config_;
159:   Filters::Common::ExtAuthz::ClientPtr client_;
160:   Network::ReadFilterCallbacks* filter_callbacks_{};
161:   Status status_{Status::NotStarted};
162:   FilterReturn filter_return_{FilterReturn::Stop};
163:   // Used to identify if the callback to onComplete() is synchronous (on the stack) or asynchronous.
164:   bool calling_check_{};
165:   envoy::service::auth::v3::CheckRequest check_request_{};
166: };
