25: using MetadataProto = ::envoy::config::core::v3::Metadata;
26: 
27: void fillMetadataContext(const MetadataProto& source_metadata,
28:                          const std::vector<std::string>& metadata_context_namespaces,
29:                          const std::vector<std::string>& typed_metadata_context_namespaces,
30:                          MetadataProto& metadata_context) {
31:   const auto& filter_metadata = source_metadata.filter_metadata();
32:   for (const auto& context_key : metadata_context_namespaces) {
33:     if (const auto metadata_it = filter_metadata.find(context_key);
34:         metadata_it != filter_metadata.end()) {
35:       (*metadata_context.mutable_filter_metadata())[metadata_it->first] = metadata_it->second;
36:     }
37:   }
38: 
39:   const auto& typed_filter_metadata = source_metadata.typed_filter_metadata();
40:   for (const auto& context_key : typed_metadata_context_namespaces) {
41:     if (const auto metadata_it = typed_filter_metadata.find(context_key);
42:         metadata_it != typed_filter_metadata.end()) {
43:       (*metadata_context.mutable_typed_filter_metadata())[metadata_it->first] = metadata_it->second;
44:     }
45:   }
46: }
47: 
48: } // namespace
