50: InstanceStats Config::generateStats(const std::string& name, Stats::Scope& scope) {
51:   const std::string final_prefix = fmt::format("ext_authz.{}.", name);
52:   return {ALL_TCP_EXT_AUTHZ_STATS(POOL_COUNTER_PREFIX(scope, final_prefix),
53:                                   POOL_GAUGE_PREFIX(scope, final_prefix))};
54: }
55: 
56: void Filter::callCheck() {
57:   // If metadata_context_namespaces or typed_metadata_context_namespaces is specified,
58:   // pass matching filter metadata to the ext_authz service.
59:   envoy::config::core::v3::Metadata metadata_context;
60:   fillMetadataContext(filter_callbacks_->connection().streamInfo().dynamicMetadata(),
61:                       config_->metadataContextNamespaces(),
62:                       config_->typedMetadataContextNamespaces(), metadata_context);
63: 
64:   Filters::Common::ExtAuthz::CheckRequestUtils::createTcpCheck(
65:       filter_callbacks_, check_request_, config_->includePeerCertificate(),
66:       config_->includeTLSSession(), config_->destinationLabels(), std::move(metadata_context));
67:   // Store start time of ext_authz filter call
68:   start_time_ = filter_callbacks_->connection().dispatcher().timeSource().monotonicTime();
69:   status_ = Status::Calling;
70:   config_->stats().active_.inc();
71:   config_->stats().total_.inc();
72: 
73:   calling_check_ = true;
74:   client_->check(*this, check_request_, Tracing::NullSpan::instance(),
75:                  filter_callbacks_->connection().streamInfo());
76:   calling_check_ = false;
77: }
78: 
79: Network::FilterStatus Filter::onData(Buffer::Instance&, bool /* end_stream */) {
80:   if (!filterEnabled(filter_callbacks_->connection().streamInfo().dynamicMetadata())) {
81:     config_->stats().disabled_.inc();
82:     return Network::FilterStatus::Continue;
83:   }
84: 
85:   if (status_ == Status::NotStarted) {
86:     // By waiting to invoke the check at onData() the call to authorization service will have
87:     // sufficient information to fill out the checkRequest_.
88:     callCheck();
89:   }
90:   return filter_return_ == FilterReturn::Stop ? Network::FilterStatus::StopIteration
91:                                               : Network::FilterStatus::Continue;
92: }
93: 
94: Network::FilterStatus Filter::onNewConnection() {
95:   // Wait till onData() happens.
96:   return Network::FilterStatus::Continue;
97: }
98: 
99: void Filter::onEvent(Network::ConnectionEvent event) {
100:   if (event == Network::ConnectionEvent::RemoteClose ||
101:       event == Network::ConnectionEvent::LocalClose) {
102:     if (status_ == Status::Calling) {
103:       // Make sure that any pending request in the client is cancelled. This will be NOP if the
104:       // request already completed.
105:       client_->cancel();
106:       config_->stats().active_.dec();
107:     }
108:   }
109: }
110: 
111: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
112:   status_ = Status::Complete;
113:   config_->stats().active_.dec();
114: 
115:   switch (response->status) {
116:   case Filters::Common::ExtAuthz::CheckStatus::OK:
117:     config_->stats().ok_.inc();
118:     // Add duration of call to dynamic metadata if applicable
119:     if (start_time_.has_value()) {
120:       Protobuf::Value ext_authz_duration_value;
121:       auto duration = filter_callbacks_->connection().dispatcher().timeSource().monotonicTime() -
122:                       start_time_.value();
123:       ext_authz_duration_value.set_number_value(
124:           std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
125:       (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
126:           ext_authz_duration_value;
127:     }
128:     break;
129:   case Filters::Common::ExtAuthz::CheckStatus::Error:
130:     config_->stats().error_.inc();
131:     break;
132:   case Filters::Common::ExtAuthz::CheckStatus::Denied:
133:     config_->stats().denied_.inc();
134:     break;
135:   }
136: 
137:   if (!response->dynamic_metadata.fields().empty()) {
138: 
139:     filter_callbacks_->connection().streamInfo().setDynamicMetadata(
140:         NetworkFilterNames::get().ExtAuthorization, response->dynamic_metadata);
141:   }
142: 
143:   // Fail open only if configured to do so and if the check status was a error.
144:   if (response->status == Filters::Common::ExtAuthz::CheckStatus::Denied ||
145:       (response->status == Filters::Common::ExtAuthz::CheckStatus::Error &&
146:        !config_->failureModeAllow())) {
147:     config_->stats().cx_closed_.inc();
148: 
149:     if (config_->sendTlsAlertOnDenial()) {
150:       auto ssl_info = filter_callbacks_->connection().ssl();
151:       if (ssl_info != nullptr) {
152:         auto* ssl_conn_info =
153:             dynamic_cast<const Extensions::TransportSockets::Tls::ConnectionInfoImplBase*>(
154:                 ssl_info.get());
155:         if (ssl_conn_info != nullptr) {
156:           SSL* ssl = ssl_conn_info->ssl();
157:           if (ssl != nullptr) {
158:             SSL_send_fatal_alert(ssl, SSL_AD_ACCESS_DENIED);
159:           }
160:         }
161:       }
162:     }
163: 
164:     filter_callbacks_->connection().close(Network::ConnectionCloseType::NoFlush, "ext_authz_close");
165:     filter_callbacks_->connection().streamInfo().setResponseFlag(
166:         StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
167:     filter_callbacks_->connection().streamInfo().setResponseCodeDetails(
168:         response->status == Filters::Common::ExtAuthz::CheckStatus::Denied
169:             ? Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied
170:             : Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
171:   } else {
172:     // Let the filter chain continue.
173:     filter_return_ = FilterReturn::Continue;
174:     if (config_->failureModeAllow() &&
175:         response->status == Filters::Common::ExtAuthz::CheckStatus::Error) {
176:       // Status is Error and yet we are configured to allow traffic. Click a counter.
177:       config_->stats().failure_mode_allowed_.inc();
178:     }
179: 
180:     // We can get completion inline, so only call continue if that isn't happening.
181:     if (!calling_check_) {
182:       filter_callbacks_->continueReading();
183:     }
184:   }
185: }
186: 
187: } // namespace ExtAuthz
188: } // namespace NetworkFilters
189: } // namespace Extensions
190: } // namespace Envoy
