108: void GrpcClientImpl::onSuccess(std::unique_ptr<envoy::service::auth::v3::CheckResponse>&& response,
109:                                Tracing::Span& span) {
110:   ENVOY_LOG(trace, "Received CheckResponse: {}", response->DebugString());
111:   ResponsePtr authz_response = std::make_unique<Response>(Response{});
112:   authz_response->grpc_status = response->status().code();
113:   if (response->status().code() == Grpc::Status::WellKnownGrpcStatus::Ok) {
114:     span.setTag(TracingConstants::get().TraceStatus, TracingConstants::get().TraceOk);
115:     authz_response->status = CheckStatus::OK;
116:     if (response->has_ok_response()) {
117:       const auto& ok_response = response->ok_response();
118:       copyOkResponseMutations(authz_response, ok_response);
119:     }
120:   } else if (response->has_error_response()) {
121:     // If error_response is present, treat it as an error and not denial.
122:     span.setTag(TracingConstants::get().TraceStatus, TracingConstants::get().TraceError);
123:     authz_response->status = CheckStatus::Error;
124: 
125:     // For error responses, don't set a default status_code.
126:     // Let the filter use status_on_error configuration.
127:     const auto& error_response = response->error_response();
128:     copyHeaderFieldIntoResponse(authz_response, error_response.headers());
129: 
130:     const uint32_t status_code = error_response.status().code();
131:     if (status_code > 0) {
132:       authz_response->status_code = static_cast<Http::Code>(status_code);
133:     }
134:     authz_response->body = error_response.body();
135:   } else {
136:     span.setTag(TracingConstants::get().TraceStatus, TracingConstants::get().TraceUnauthz);
137:     authz_response->status = CheckStatus::Denied;
138: 
139:     // The default HTTP status code for denied response is 403 Forbidden.
140:     authz_response->status_code = Http::Code::Forbidden;
141:     if (response->has_denied_response()) {
142:       copyHeaderFieldIntoResponse(authz_response, response->denied_response().headers());
143: 
144:       const uint32_t status_code = response->denied_response().status().code();
145:       if (status_code > 0) {
146:         authz_response->status_code = static_cast<Http::Code>(status_code);
147:       }
148:       authz_response->body = response->denied_response().body();
149:     }
150:   }
151: 
152:   // OkHttpResponse.dynamic_metadata is deprecated. Until OkHttpResponse.dynamic_metadata is
153:   // removed, it overrides dynamic_metadata field of the outer check response.
154:   if (response->has_ok_response() && response->ok_response().has_dynamic_metadata()) {
155:     authz_response->dynamic_metadata = response->ok_response().dynamic_metadata();
156:   } else {
157:     authz_response->dynamic_metadata = response->dynamic_metadata();
158:   }
159: 
160:   callbacks_->onComplete(std::move(authz_response));
161:   callbacks_ = nullptr;
162: }
