164: void GrpcClientImpl::onFailure(Grpc::Status::GrpcStatus status, const std::string&,
165:                                Tracing::Span&) {
166:   ENVOY_LOG(trace, "CheckRequest call failed with status: {}",
167:             Grpc::Utility::grpcStatusToString(status));
168:   ASSERT(status != Grpc::Status::WellKnownGrpcStatus::Ok);
169:   Response response{};
170:   response.status = CheckStatus::Error;
171:   response.grpc_status = status;
172:   callbacks_->onComplete(std::make_unique<Response>(response));
173:   callbacks_ = nullptr;
174: }
